mapper.sql:
from advisor_product p inner join sys_user u on u.id = p.creator_id inner join advisor_product_version v on v.product_id = p.id and v.version_no = p.current_version_no where p.status = 'PENDING_REVIEW' and v.version_status = 'SUBMITTED'
and ( p.name like concat('%', #{keyword}, '%') or p.strategy_code like concat('%', #{keyword}, '%') )
and p.type = #{type}
and p.risk_level = #{riskLevel}
